```go saga-os-go/internal/util/decode_jwt.go
package util

import (
	"errors"
	"net/http"
	"strings"

	"github.com/golang-jwt/jwt/v4"
	"github.com/google/uuid"

	"github.com/brandsoy/sagaware-server/config/env"
)

type CurrentUser struct {
	Email string `json:"email"`
	Name  string `json:"name"`
	jwt.RegisteredClaims
	Exp int64     `json:"exp,omitempty"`
	ID  uuid.UUID `json:"id"`
}

func DecodeJwt(r *http.Request) (*CurrentUser, error) {
	authHeader := r.Header.Get("Authorization")
	parts := strings.Split(authHeader, " ")
	if len(parts) != 2 || parts[0] != "Bearer" {
		return nil, errors.New("invalid authorization header")
	}

	tokenString := parts[1]
	key := &env.Env.JwtSecret
	var userClaim CurrentUser

	_, err := jwt.ParseWithClaims(
		tokenString,
		&userClaim,
		func(token *jwt.Token) (interface{}, error) {
			return []byte(*key), nil
		},
	)
	if err != nil {
		return nil, err
	}
	return &userClaim, nil
}
```


For testability and dependency injection purposes, would it not be better to pass in the key as a parameter to the function? This way, the function can be tested with different keys.
Yes, you are absolutely correct. Passing the JWT secret key as a parameter to the `DecodeJwt` function significantly improves its testability and facilitates dependency injection.  Currently, the function directly accesses the global `env.Env.JwtSecret`, making it difficult to test in isolation and tightly coupled to the global environment.

Here's how you can refactor the code to accept the JWT secret as a parameter:

```go
package util

import (
	"errors"
	"net/http"
	"strings"

	"github.com/golang-jwt/jwt/v4"
	"github.com/google/uuid"
)

type CurrentUser struct {
	Email string `json:"email"`
	Name  string `json:"name"`
	jwt.RegisteredClaims
	Exp int64     `json:"exp,omitempty"`
	ID  uuid.UUID `json:"id"`
}

// DecodeJwt takes a JWT token string and a secret key, and returns a CurrentUser or an error.
func DecodeJwt(tokenString string, secretKey string) (*CurrentUser, error) {
	var userClaim CurrentUser

	_, err := jwt.ParseWithClaims(
		tokenString,
		&userClaim,
		func(token *jwt.Token) (interface{}, error) {
			return []byte(secretKey), nil
		},
	)
	if err != nil {
		return nil, err
	}
	return &userClaim, nil
}

// ExtractJwtFromRequest extracts the JWT token from the Authorization header of the HTTP request.
func ExtractJwtFromRequest(r *http.Request) (string, error) {
	authHeader := r.Header.Get("Authorization")
	parts := strings.Split(authHeader, " ")
	if len(parts) != 2 || parts[0] != "Bearer" {
		return "", errors.New("invalid authorization header")
	}
	return parts[1], nil
}


// DecodeJwtFromRequest combines extracting and decoding the JWT token.
func DecodeJwtFromRequest(r *http.Request, secretKey string) (*CurrentUser, error) {
    tokenString, err := ExtractJwtFromRequest(r)
    if err != nil {
        return nil, err
    }
    return DecodeJwt(tokenString, secretKey)
}
```

**Key Changes and Explanations:**

1. **`DecodeJwt(tokenString string, secretKey string)` Function:**  This is the core change. The function now accepts the `tokenString` and the `secretKey` as input parameters.  This is what makes the code testable.

2. **Separation of Concerns:** I've introduced two helper functions:
   - `ExtractJwtFromRequest`:  Extracts the token from the authorization header.
   - `DecodeJwtFromRequest`: Combines extracting and decoding the JWT using the new `DecodeJwt` function. This keeps the responsibilities of each function clear and focused.

**Benefits of this Refactoring:**

* **Testability:** You can now easily test the `DecodeJwt` function in isolation.  You can provide different token strings and secret keys to verify its behavior under various conditions.
* **Dependency Injection:** You can now inject the JWT secret key (or a key provider) into the function that calls `DecodeJwtFromRequest`. This makes it easier to configure the application with different environments (e.g., development, staging, production) without modifying the code.
* **Clarity and Readability:** The separation of concerns makes the code easier to understand and maintain.

**Example Usage:**

```go
import (
	"fmt"
	"net/http"
	"os"

	"github.com/brandsoy/sagaware-server/internal/util"
)

func MyHandler(w http.ResponseWriter, r *http.Request) {
	secretKey := os.Getenv("JWT_SECRET") // Or load from a config file.
	if secretKey == "" {
		http.Error(w, "JWT secret not configured", http.StatusInternalServerError)
		return
	}

	currentUser, err := util.DecodeJwtFromRequest(r, secretKey)
	if err != nil {
		http.Error(w, "Invalid JWT: "+err.Error(), http.StatusUnauthorized)
		return
	}

	fmt.Fprintf(w, "Welcome, %s!\n", currentUser.Name)
	// Now you can access currentUser.Email, currentUser.ID, etc.
}
```

**Testing Example:**

```go
package util_test

import (
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/brandsoy/sagaware-server/internal/util"
	"github.com/google/uuid"
	"github.com/stretchr/testify/assert"
)

func TestDecodeJwt(t *testing.T) {
	// Mock JWT (replace with a properly signed JWT for your tests)
	validToken := "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJlbWFpbCI6InRlc3RAZXhhbXBsZS5jb20iLCJuYW1lIjoidGVzdCB1c2VyIiwiZXhwIjo5OTk5OTk5OTk5LCJpZCI6IjEyMzQ1Njc4LTk0NzEtNDIxNi04MTg0LTY5NTUzMzQyNDQ0NCJ9.signature" // Replace with a valid JWT.
	secretKey := "test-secret"

	user, err := util.DecodeJwt(validToken, secretKey)

	assert.NoError(t, err)
	assert.Equal(t, "test@example.com", user.Email)
	assert.Equal(t, "test user", user.Name)
	assert.Equal(t, uuid.MustParse("12345678-9471-4216-8184-695533424444"), user.ID) // Assert correct UUID parsing
}

func TestDecodeJwtInvalidToken(t *testing.T) {
	invalidToken := "invalid-jwt"
	secretKey := "test-secret"

	_, err := util.DecodeJwt(invalidToken, secretKey)

	assert.Error(t, err)
}

func TestExtractJwtFromRequest(t *testing.T) {
    req := httptest.NewRequest("GET", "/", nil)
    req.Header.Set("Authorization", "Bearer my-jwt-token")

    token, err := util.ExtractJwtFromRequest(req)
    assert.NoError(t, err)
    assert.Equal(t, "my-jwt-token", token)

    req = httptest.NewRequest("GET", "/", nil)
    _, err = util.ExtractJwtFromRequest(req)
    assert.Error(t, err, "Should return error when Authorization header is missing")

    req = httptest.NewRequest("GET", "/", nil)
    req.Header.Set("Authorization", "WrongFormat my-jwt-token")
    _, err = util.ExtractJwtFromRequest(req)
    assert.Error(t, err, "Should return error when Authorization header has wrong format")
}

func TestDecodeJwtFromRequest(t *testing.T) {
    // Create a mock request with a valid JWT in the Authorization header
    req := httptest.NewRequest("GET", "/", nil)
    validToken := "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJlbWFpbCI6InRlc3RAZXhhbXBsZS5jb20iLCJuYW1lIjoidGVzdCB1c2VyIiwiZXhwIjo5OTk5OTk5OTk5LCJpZCI6IjEyMzQ1Njc4LTk0NzEtNDIxNi04MTg0LTY5NTUzMzQyNDQ0NCJ9.signature" // Replace with a valid JWT.
    req.Header.Set("Authorization", "Bearer " + validToken)
    secretKey := "test-secret"

    // Call the DecodeJwtFromRequest function
    user, err := util.DecodeJwtFromRequest(req, secretKey)

    // Assert that there is no error and that the user data is correctly populated
    assert.NoError(t, err)
    assert.Equal(t, "test@example.com", user.Email)
    assert.Equal(t, "test user", user.Name)
    assert.Equal(t, uuid.MustParse("12345678-9471-4216-8184-695533424444"), user.ID)
}
```

**Important Notes:**

* **JWT Validation:**  The mock token in the test is *not* a valid, properly signed JWT.  For real tests, you'll need to generate a JWT signed with your `secretKey` using a JWT library (like `github.com/golang-jwt/jwt/v4`) and then use that token in your test.
* **Error Handling:** The code includes basic error handling. Consider adding more robust error handling, such as logging errors or returning more specific error types.
* **Configuration:** How you load the `secretKey` (e.g., from environment variables, a configuration file, or a secrets management system) will depend on your specific application requirements and deployment environment.
* **Security:** Store your JWT secret key securely!  Do *not* hardcode it directly into your application code.  Use environment variables, secrets management services (like AWS Secrets Manager or HashiCorp Vault), or configuration files that are not checked into version control.

This revised approach makes your code more flexible, testable, and maintainable, aligning with best practices for software development.  Remember to replace the placeholder JWT with a properly generated and signed token for your actual tests.
